import { createTwilioMessage } from './twilio';
import { createSendGridMail } from './sendgrid';
const axios = require('axios');

 async function sendMessages(event){
  const [twilio, sendGrid] = await Promise.all([
    axios({
      method: 'get', 
      url: 'http://localhost:8082/' 
    }),
    axios({
      method: 'get',
      url: 'http://localhost:3001'
    }) 
  ]);

  const twilioResponse = JSON.parse(twilio);
  const sendGridResponse = JSON.parse(sendgrid);
  let response;
  if (twilioResponse === 200) { 
    response = await createTwilioMessage(event, twilioResponse); } 
  else {
    response = await createSendGridMail(event, sendGridResponse); 
  }
}

 export default { 
    handler: async event => await sendMessages(event),
 };